    89→// processPanelsV38 recursively processes panels, including nested panels within rows
    90→func processPanelsV38(panels []interface{}) {
    91→	for _, panel := range panels {
    92→		p, ok := panel.(map[string]interface{})
    93→		if !ok {
    94→			continue
    95→		}
    96→
    97→		// Process nested panels if this is a row panel
    98→		if p["type"] == "row" {
    99→			if nestedPanels, ok := p["panels"].([]interface{}); ok {
   100→				processPanelsV38(nestedPanels)
   101→			}
   102→			continue
   103→		}
   104→
   105→		// Only process table panels
   106→		if p["type"] != "table" {
   107→			continue
   108→		}
   109→
   110→		fieldConfig, ok := p["fieldConfig"].(map[string]interface{})
   111→		if !ok {
   112→			continue
   113→		}
   114→
   115→		defaults, ok := fieldConfig["defaults"].(map[string]interface{})
   116→		if !ok {
   117→			continue
   118→		}
   119→
   120→		custom, ok := defaults["custom"].(map[string]interface{})
   121→		if !ok {
   122→			continue
   123→		}
   124→
   125→		// Migrate displayMode to cellOptions
   126→		if displayMode, exists := custom["displayMode"]; exists {
   127→			if displayModeStr, ok := displayMode.(string); ok {
   128→				custom["cellOptions"] = migrateTableDisplayModeToCellOptions(displayModeStr)
   129→			}
   130→			// Delete the legacy field
   131→			delete(custom, "displayMode")
   132→		}
   133→
   134→		// Update any overrides referencing the cell display mode
   135→		migrateOverrides(fieldConfig)
   136→	}
   137→}
