   139→// migrateOverrides updates the overrides configuration to use the new cellOptions format
   140→func migrateOverrides(fieldConfig map[string]interface{}) {
   141→	overrides, ok := fieldConfig["overrides"].([]interface{})
   142→	if !ok {
   143→		return
   144→	}
   145→
   146→	for _, override := range overrides {
   147→		o, ok := override.(map[string]interface{})
   148→		if !ok {
   149→			continue
   150→		}
   151→
   152→		properties, ok := o["properties"].([]interface{})
   153→		if !ok {
   154→			continue
   155→		}
   156→
   157→		for _, property := range properties {
   158→			prop, ok := property.(map[string]interface{})
   159→			if !ok {
   160→				continue
   161→			}
   162→
   163→			// Update the id to cellOptions
   164→			if prop["id"] == "custom.displayMode" {
   165→				prop["id"] = "custom.cellOptions"
   166→				if value, ok := prop["value"]; ok {
   167→					if valueStr, ok := value.(string); ok {
   168→						prop["value"] = migrateTableDisplayModeToCellOptions(valueStr)
   169→					}
   170→				} else {
   171→					// If no value exists, add empty cellOptions object to match frontend behavior
   172→					// Frontend always assigns a value even when original displayMode had no value
   173→					// See: public/app/features/dashboard/state/DashboardMigrator.ts:880
   174→					// override.properties[j].value = migrateTableDisplayModeToCellOptions(overrideDisplayMode);
   175→					prop["value"] = map[string]interface{}{}
   176→				}
   177→			}
   178→		}
   179→	}
   180→}
